21	pub fn call_builtin(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
22	    // Try math/constructor builtins first
23	    if let Some(result) = math_builtins::try_call(name, args.clone()) {
24	        return result;
25	    }
26	    if let Some(result) = crate::random_builtins::try_call(name, args.clone()) {
27	        return result;
28	    }
29	    if let Some(result) = crate::dataset_builtins::try_call(name, args.clone()) {
30	        return result;
31	    }
32	    if let Some(result) = crate::ml_builtins::try_call(name, args.clone()) {
33	        return result;
34	    }
35	    match name {
36	        "iota" => builtin_iota(name, args),
37	        "shape" => builtin_shape(name, args),
38	        "rank" => builtin_rank(name, args),
39	        "reshape" => builtin_reshape(name, args),
40	        "transpose" => builtin_transpose(name, args),
41	        "reduce_add" | "reduce_mul" => builtin_reduce(name, args),
42	        "argmax" => builtin_argmax(name, args),
43	        "dot" => {
44	            check_arity!(name, 2, args);
45	            Ok(args[0].dot(&args[1])?)
46	        }
47	        "matmul" => {
48	            check_arity!(name, 2, args);
49	            Ok(args[0].matmul(&args[1])?)
50	        }
51	        "grid" => crate::grid_builtin::builtin_grid(name, args),
52	        _ => Err(RuntimeError::UnknownFunction(name.into())),
53	    }
54	}
