56	fn builtin_iota(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
57	    check_arity!(name, 1, args);
58	    if args[0].rank() != 0 {
59	        return Err(RuntimeError::InvalidArgument {
60	            func: name.into(),
61	            reason: format!("expected scalar, got rank {}", args[0].rank()),
62	        });
63	    }
64	    let n = args[0].data()[0] as usize;
65	    let data: Vec<f64> = (0..n).map(|i| i as f64).collect();
66	    Ok(DenseArray::from_vec(data))
67	}
