92	fn builtin_argmax(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
93	    if args.len() == 1 {
94	        // Flat argmax over all elements, returned as a scalar index.
95	        let data = args[0].data();
96	        if data.is_empty() {
97	            return Err(RuntimeError::InvalidArgument {
98	                func: name.into(),
99	                reason: "argmax of empty array".into(),
100	            });
101	        }
102	        let mut best_idx = 0usize;
103	        let mut best_val = data[0];
104	        for (i, &v) in data.iter().enumerate().skip(1) {
105	            if v > best_val {
106	                best_val = v;
107	                best_idx = i;
108	            }
109	        }
110	        return Ok(DenseArray::from_scalar(best_idx as f64));
111	    }
112	    if args.len() != 2 {
113	        return Err(RuntimeError::ArityMismatch {
114	            func: name.into(),
115	            expected: 2,
116	            got: args.len(),
117	        });
118	    }
119	    if args[1].rank() != 0 {
120	        return Err(RuntimeError::InvalidArgument {
121	            func: name.into(),
122	            reason: format!("axis must be scalar, got rank {}", args[1].rank()),
123	        });
124	    }
125	    let axis = args[1].data()[0] as usize;
126	    Ok(args[0].argmax_axis(axis)?)
127	}
