    let lse: Vec<f64> = sums
        .iter()
        .zip(maxv.iter())
        .map(|(s, m)| m + s.ln())
        .collect();
    let mut out = vec![0.0f64; a.elem_count()];
    for (flat, slot) in out.iter_mut().enumerate() {
        *slot = a.data()[flat] - lse[group_of(flat)];
    }
    finalize_same_shape(a, dims, out)
}

/// `cross_entropy(logits, targets)`: fused log-softmax + NLL,
/// returned as a scalar mean over rows. `logits` must be rank 2
/// (`[N, V]`) or rank 3 (`[B, T, V]`); `targets` must hold
/// non-negative integer values whose count equals the row count
/// (`N` or `B*T`). Always returns an unlabeled scalar, matching
/// the CPU `mlpl_runtime::call_builtin("cross_entropy", _)`
/// behaviour.
pub fn cross_entropy(
    logits: &DenseArray,
    targets: &DenseArray,
) -> Result<DenseArray, ArrayError> {
    let (n, v, idx) = ce_indices(logits, targets)?;
    let data = logits.data();
    let mut total = 0.0;
    for (i, &t) in idx.iter().enumerate() {
        let row = &data[i * v..(i + 1) * v];
        let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
        let lse = m + row.iter().map(|x| (x - m).exp()).sum::<f64>().ln();
        total += lse - row[t];
    }
    Ok(DenseArray::from_scalar(total / n as f64))
}

/// Compute `(axis_size, axis_stride)` for a row-major shape.
fn axis_metrics(dims: &[usize], axis: usize) -> (usize, usize) {
    let mut stride = 1usize;
    for d in dims.iter().skip(axis + 1) {
        stride *= d;
    }
    (dims[axis], stride)
}

/// Map a flat index to its softmax-group index (the flat index
/// with the chosen axis coordinate removed).
fn group_index(flat: usize, axis_size: usize, axis_stride: usize) -> usize {
    if axis_stride > 1 {
        let outer = flat / (axis_size * axis_stride);
        let inner = flat % axis_stride;
        outer * axis_stride + inner
    } else {
        flat / axis_size
    }
}

/// Wrap shape-preserving output as a `DenseArray` with `a`'s labels.
fn finalize_same_shape(
    a: &DenseArray,
    dims: Vec<usize>,
    data: Vec<f64>,
) -> Result<DenseArray, ArrayError> {
    let out = DenseArray::new(Shape::new(dims), data)?;
    match a.labels() {
        Some(lbls) => out.with_labels(lbls.to_vec()),
        None => Ok(out),
    }
}

/// Validate logits/targets and unpack the row-major flat index list.
fn ce_indices(
    logits: &DenseArray,
    targets: &DenseArray,
) -> Result<(usize, usize, Vec<usize>), ArrayError> {
    let dims = logits.shape().dims();
    let (n, v) = match dims.len() {
        2 => (dims[0], dims[1]),
        3 => (dims[0] * dims[1], dims[2]),
        r => {
            return Err(ArrayError::RankMismatch {
                expected: 2,
                got: r,
            });
        }
    };
    if targets.elem_count() != n {
        return Err(ArrayError::ShapeMismatch {
            source: n,
            target: targets.elem_count(),
        });
    }
    let mut idx = Vec::with_capacity(n);
    for (i, &t) in targets.data().iter().enumerate() {
        if t < 0.0 || t.fract() != 0.0 {
            return Err(ArrayError::IndexOutOfBounds {
                axis: 0,
                index: i,
                size: v,
            });
        }
        let ti = t as usize;
        if ti >= v {
            return Err(ArrayError::IndexOutOfBounds {
                axis: 0,
                index: ti,
                size: v,
            });
        }
        idx.push(ti);
    }
    Ok((n, v, idx))
}

