/// `[T]` integer ids -> `[T, V]` one-hot matrix (row-major).
fn tokens_to_onehot(tokens: &DenseArray) -> DenseArray {
    let n = tokens.shape().dims()[0];
    let mut data = vec![0.0_f64; n * V];
    for (row, &t) in tokens.data().iter().enumerate() {
        let id = t as usize;
