    let masked_arr = DenseArray::new(Shape::new(vec![T, T]), masked)?;
    let attn = (b.softmax)(&masked_arr, 1)?;
    let head_out = (b.matmul)(&attn, v.shape().dims().first().map(|_| &v).unwrap())?;
