1	//! MLX-backed reductions, normalisation, and loss primitives
2	//! (Saga 14 step 003).
3	//!
4	//! Signatures mirror `mlpl-rt::reductions` so compiled MLPL code
5	//! can swap runtimes without source changes:
6	//!
7	//! - `reduce_mul` / `mean` / `argmax` take `Option<usize>` axis
8	//!   (None = flat reduction over the whole array).
9	//! - `softmax` / `log_softmax` take `usize` axis.
10	//! - `cross_entropy(logits, targets)` is a fused log-softmax + NLL
11	//!   that returns an unlabeled scalar mean.
12	//!
13	//! Validation (axis bounds, target integrality, target range) lives
14	//! on the Rust side so MLX sees only legal inputs. Numerical work
15	//! routes through MLX's own kernels (`prod`, `mean`, `argmax`,
16	//! `softmax_axis`, `log_softmax`, `logsumexp_axis`); the fp32
17	//! GPU/Accelerate path means parity tests use a documented
18	//! tolerance rather than bit-for-bit equality. Label propagation
19	//! follows Saga 11.5: reductions drop the reduced axis label,
20	//! softmax/log_softmax preserve labels, cross_entropy returns
21	//! unlabeled.
22	
23	use mlpl_array::{ArrayError, DenseArray, Shape};
24	
25	use crate::common::{dense_to_mlx, finalize, mlx_to_dense_data};
26	
27	/// Product reduction over `axis` (None = flat).
28	pub fn reduce_mul(a: &DenseArray, axis: Option<usize>) -> Result<DenseArray, ArrayError> {
29	    let mlx = dense_to_mlx(a.data(), a.shape().dims());
30	    if let Some(ax) = axis {
31	        let dims = a.shape().dims();
32	        if ax >= dims.len() {
33	            return Err(ArrayError::IndexOutOfBounds {
34	                axis: ax,
35	                index: ax,
36	                size: dims.len(),
37	            });
38	        }
39	        let reduced = mlx
40	            .prod_axis(ax as i32, false)
41	            .expect("mlx prod_axis on validated axis");
42	        let (out_dims, labels) = drop_axis(a, ax);
43	        return finalize(Shape::new(out_dims), mlx_to_dense_data(reduced), labels);
44	    }
45	    let reduced = mlx.prod(false).expect("mlx prod on validated array");
46	    finalize(Shape::new(vec![]), mlx_to_dense_data(reduced), None)
47	}
48	
49	/// Mean reduction over `axis` (None = flat).
50	pub fn mean(a: &DenseArray, axis: Option<usize>) -> Result<DenseArray, ArrayError> {
51	    let mlx = dense_to_mlx(a.data(), a.shape().dims());
52	    if let Some(ax) = axis {
53	        let dims = a.shape().dims();
54	        if ax >= dims.len() {
55	            return Err(ArrayError::IndexOutOfBounds {
56	                axis: ax,
57	                index: ax,
58	                size: dims.len(),
59	            });
60	        }
61	        let reduced = mlx
62	            .mean_axis(ax as i32, false)
63	            .expect("mlx mean_axis on validated axis");
64	        let (out_dims, labels) = drop_axis(a, ax);
65	        return finalize(Shape::new(out_dims), mlx_to_dense_data(reduced), labels);
66	    }
67	    let reduced = mlx.mean(false).expect("mlx mean on validated array");
68	    finalize(Shape::new(vec![]), mlx_to_dense_data(reduced), None)
69	}
