104	/// `softmax(a, axis)` via MLX's stable kernel. Output shape and
105	/// labels match the input.
106	pub fn softmax(a: &DenseArray, axis: usize) -> Result<DenseArray, ArrayError> {
107	    let dims = a.shape().dims().to_vec();
108	    if axis >= dims.len() {
109	        return Err(ArrayError::IndexOutOfBounds {
110	            axis,
111	            index: axis,
112	            size: dims.len(),
113	        });
114	    }
