116	    let result = mlx_rs::ops::softmax_axis(&mlx, axis as i32, false)
117	        .expect("mlx softmax_axis on validated input");
118	    finalize(
119	        Shape::new(dims),
120	        mlx_to_dense_data(result),
121	        a.labels().map(<[Option<String>]>::to_vec),
122	    )
123	}
