1	//! Saga 14 step 003 closing test: a Tiny LM forward pass routed
2	//! through the MLX runtime produces the same loss as the same
3	//! forward routed through `mlpl-rt`, within fp32 tolerance.
4	//!
5	//! The forward exercises every primitive the Saga 13 Tiny LM
6	//! `demos/tiny_lm.mlpl` uses through to its loss scalar:
7	//!
8	//!     embed -> positional -> rms_norm -> causal_attention
9	//!           -> residual -> rms_norm -> linear -> relu -> linear
10	//!           -> residual -> rms_norm -> linear -> cross_entropy
11	//!
12	//! The model is a single head, single block, scaled down to keep
13	//! the test cheap (V=8, d=4, T=4, ff_hidden=8) but structurally
14	//! identical to the demo. A `Backend` function-pointer table lets
15	//! the same forward run on either runtime; passing the test means
16	//! the MLX path produces the same loss as the CPU path on the
17	//! same fixed-seed parameters.
18	//!
19	//! Same triple-gate as the rest of `mlpl-mlx`: macOS + aarch64 +
20	//! `mlx` feature.
21	
22	#![cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
23	
24	use mlpl_mlx::{ArrayError, DenseArray, Shape};
25	
26	/// Tolerance for the end-to-end forward parity. The Tiny LM
27	/// forward chains ~10 fp32-round-tripped MLX kernels; the
28	/// per-element error compounds roughly linearly. 5e-4 is loose
29	/// enough to absorb that compounding while still catching real
30	/// regressions.
31	const TINY_LM_TOL: f64 = 5e-4;
32	
33	/// Per-runtime function pointers for every primitive the forward
34	/// touches. Pure Rust scaffolding (slice_cols, rms_norm by hand,
35	/// mask construction) lives outside the table so it is shared
36	/// across runtimes verbatim.
37	struct Backend {
38	    matmul: fn(&DenseArray, &DenseArray) -> Result<DenseArray, ArrayError>,
39	    add: fn(&DenseArray, &DenseArray) -> Result<DenseArray, ArrayError>,
40	    softmax: fn(&DenseArray, usize) -> Result<DenseArray, ArrayError>,
41	    transpose: fn(&DenseArray) -> DenseArray,
42	    relu: fn(&DenseArray) -> DenseArray,
43	    cross_entropy: fn(&DenseArray, &DenseArray) -> Result<DenseArray, ArrayError>,
44	}
45	
46	/// CPU matmul wrapper -- `mlpl-rt` does not surface a free
47	/// `matmul` symbol because the compile-to-rust codegen lowers it
48	/// to a direct `DenseArray::matmul` method call. The MLX side does
49	/// have a free `mlpl_mlx::matmul`, so we wrap the CPU side here to
50	/// give the `Backend` table a uniform signature.
51	fn cpu_matmul(a: &DenseArray, b: &DenseArray) -> Result<DenseArray, ArrayError> {
52	    a.matmul(b)
53	}
54	
55	const MLPL_RT: Backend = Backend {
56	    matmul: cpu_matmul,
57	    add: mlpl_rt::add,
58	    softmax: mlpl_rt::softmax,
59	    transpose: mlpl_rt::transpose,
60	    relu: mlpl_rt::relu,
61	    cross_entropy: mlpl_rt::cross_entropy,
62	};
63	
64	const MLPL_MLX: Backend = Backend {
65	    matmul: mlpl_mlx::matmul,
66	    add: mlpl_mlx::add,
67	    softmax: mlpl_mlx::softmax,
68	    transpose: mlpl_mlx::transpose,
69	    relu: mlpl_mlx::relu,
70	    cross_entropy: mlpl_mlx::cross_entropy,
71	};
72	
73	#[test]
74	fn tiny_lm_forward_loss_matches_cpu_within_tolerance() {
75	    let p = Params::new();
76	    let cpu_loss = forward_loss(&MLPL_RT, &p).unwrap();
77	    let mlx_loss = forward_loss(&MLPL_MLX, &p).unwrap();
78	    assert_eq!(cpu_loss.shape().dims(), &[] as &[usize]);
79	    assert_eq!(mlx_loss.shape().dims(), &[] as &[usize]);
80	    let diff = (cpu_loss.data()[0] - mlx_loss.data()[0]).abs();
81	    assert!(
82	        diff <= TINY_LM_TOL,
83	        "tiny LM forward loss diverges: cpu={} mlx={} diff={} tol={TINY_LM_TOL}",
84	        cpu_loss.data()[0],
85	        mlx_loss.data()[0],
86	        diff
87	    );
88	}
89	
90	/// Tiny LM hyperparameters and frozen parameters. All weights are
91	/// produced by a deterministic PRNG so both backends see exactly
92	/// the same inputs.
93	struct Params {
94	    embed: DenseArray,   // [V, d]
95	    pos: DenseArray,     // [T, d]
96	    wq: DenseArray,      // [d, d]
97	    wk: DenseArray,      // [d, d]
98	    wv: DenseArray,      // [d, d]
99	    wo: DenseArray,      // [d, d]
100	    w1: DenseArray,      // [d, ff]
101	    w2: DenseArray,      // [ff, d]
102	    w_out: DenseArray,   // [d, V]
103	    tokens: DenseArray,  // [T] -- input ids as f64
104	    targets: DenseArray, // [T] -- next-token ids as f64
105	}
106	
107	const V: usize = 8;
108	const D: usize = 4;
109	const T: usize = 4;
110	const FF: usize = 8;
111	
112	impl Params {
113	    fn new() -> Self {
114	        let mut rng = 0x9E37_79B9_u32;
115	        let mut next = || {
116	            // splitmix32-ish: deterministic, dependency-free.
117	            rng = rng.wrapping_mul(0x85EB_CA6B).wrapping_add(0xC2B2_AE35);
118	            ((rng >> 8) as f64) / (1u32 << 24) as f64 - 0.5
119	        };
120	        let mat = |rows: usize, cols: usize, sample: &mut dyn FnMut() -> f64| {
121	            let data: Vec<f64> = (0..rows * cols).map(|_| sample()).collect();
122	            DenseArray::new(Shape::new(vec![rows, cols]), data).unwrap()
123	        };
124	        let embed = mat(V, D, &mut next);
125	        let pos = mat(T, D, &mut next);
126	        let wq = mat(D, D, &mut next);
127	        let wk = mat(D, D, &mut next);
128	        let wv = mat(D, D, &mut next);
129	        let wo = mat(D, D, &mut next);
130	        let w1 = mat(D, FF, &mut next);
131	        let w2 = mat(FF, D, &mut next);
132	        let w_out = mat(D, V, &mut next);
133	        let tokens = DenseArray::from_vec(vec![1.0, 3.0, 5.0, 7.0]);
134	        let targets = DenseArray::from_vec(vec![2.0, 4.0, 6.0, 0.0]);
135	        Self {
136	            embed,
137	            pos,
138	            wq,
139	            wk,
140	            wv,
141	            wo,
142	            w1,
143	            w2,
144	            w_out,
145	            tokens,
146	            targets,
147	        }
148	    }
149	}
150	
151	/// Run the full Tiny LM forward and return the cross_entropy loss.
152	fn forward_loss(b: &Backend, p: &Params) -> Result<DenseArray, ArrayError> {
153	    let onehot = tokens_to_onehot(&p.tokens);
154	    let emb = (b.matmul)(&onehot, &p.embed)?;
155	    let h0 = (b.add)(&emb, &p.pos)?;
156	
157	    let attn_in = rms_norm(&h0);
158	    let attn_out = causal_attention(b, &attn_in, &p.wq, &p.wk, &p.wv, &p.wo)?;
159	    let h1 = (b.add)(&h0, &attn_out)?;
160	
161	    let ff_in = rms_norm(&h1);
162	    let ff_h = (b.matmul)(&ff_in, &p.w1)?;
163	    let ff_act = (b.relu)(&ff_h);
164	    let ff_out = (b.matmul)(&ff_act, &p.w2)?;
165	    let h2 = (b.add)(&h1, &ff_out)?;
166	
167	    let final_norm = rms_norm(&h2);
168	    let logits = (b.matmul)(&final_norm, &p.w_out)?;
169	    (b.cross_entropy)(&logits, &p.targets)
170	}
171	
172	/// `[T]` integer ids -> `[T, V]` one-hot matrix (row-major).
173	fn tokens_to_onehot(tokens: &DenseArray) -> DenseArray {
174	    let n = tokens.shape().dims()[0];
175	    let mut data = vec![0.0_f64; n * V];
176	    for (row, &t) in tokens.data().iter().enumerate() {
177	        let id = t as usize;
178	        data[row * V + id] = 1.0;
179	    }
180	    DenseArray::new(Shape::new(vec![n, V]), data).unwrap()
181	}
182	
183	/// Per-row RMS norm: `y[i, :] = x[i, :] / sqrt(mean(x[i, :]^2) + eps)`.
184	/// Pure Rust so it is identical for both backends; the parity test
185	/// is about MLX vs CPU on shared scaffolding, not about RMS norm
186	/// going through MLX.
187	fn rms_norm(x: &DenseArray) -> DenseArray {
188	    let dims = x.shape().dims().to_vec();
189	    let rows = dims[0];
190	    let cols = dims[1];
191	    let eps = 1e-8;
192	    let src = x.data();
193	    let mut out = Vec::with_capacity(src.len());
194	    for r in 0..rows {
195	        let row = &src[r * cols..(r + 1) * cols];
196	        let mean_sq: f64 = row.iter().map(|v| v * v).sum::<f64>() / cols as f64;
197	        let scale = 1.0 / (mean_sq + eps).sqrt();
198	        for v in row {
199	            out.push(v * scale);
200	        }
201	    }
202	    DenseArray::new(Shape::new(dims), out).unwrap()
203	}
