1	//! Statement-shaped parser methods split out of `parser.rs` so that
2	//! module stays under the sw-checklist function-count budget.
3	//!
4	//! Every method here takes `&mut Parser` as the receiver via an
5	//! inherent-impl extension block. Saga 12 step 003 extraction
6	//! point.
7	
8	use mlpl_core::Span;
9	
10	use crate::ast::Expr;
11	use crate::error::{ParseError, describe_kind};
12	use crate::parser::Parser;
13	use crate::token::TokenKind;
14	
15	impl Parser<'_> {
16	    /// Parse `name : [axis1, axis2, ...] = value` and desugar to
17	    /// `Assign { name, value: FnCall("label", [value, ArrayLit([StrLit(a1), ...])]) }`.
18	    /// Saga 11.5 Phase 2. An empty list `[]` is legal and means
19	    /// "scalar with no axes".
20	    pub(crate) fn parse_annotated_assign(&mut self) -> Result<Expr, ParseError> {
21	        let start = self.tokens[self.pos].span;
22	        let TokenKind::Ident(n) = &self.tokens[self.pos].kind else {
23	            unreachable!()
24	        };
25	        let name = n.clone();
26	        self.pos += 2; // skip name and ':'
27	        let br_start = self.expect(&TokenKind::LBracket)?;
28	        let mut labels: Vec<Expr> = Vec::new();
29	        while !self.is(TokenKind::RBracket) {
30	            let tok = &self.tokens[self.pos];
31	            let TokenKind::Ident(a) = &tok.kind else {
32	                return Err(ParseError::UnexpectedToken {
33	                    found: describe_kind(&tok.kind),
34	                    span: tok.span,
35	                });
36	            };
37	            labels.push(Expr::StrLit(a.clone(), tok.span));
38	            self.pos += 1;
39	            if self.is(TokenKind::Comma) {
40	                self.pos += 1;
41	            } else {
42	                break;
43	            }
44	        }
45	        let br_end = self.expect(&TokenKind::RBracket)?;
46	        self.expect(&TokenKind::Equals)?;
47	        let value = self.parse_expr(0)?;
48	        let value_span = value.span();
49	        let call = Expr::FnCall {
50	            name: "label".into(),
51	            args: vec![
52	                value,
53	                Expr::ArrayLit(labels, Span::new(br_start.start, br_end.end)),
54	            ],
55	            span: Span::new(br_start.start, value_span.end),
56	        };
57	        Ok(Expr::Assign {
58	            name,
59	            value: Box::new(call),
60	            span: Span::new(start.start, value_span.end),
61	        })
62	    }
63	
64	    /// Parse `experiment "name" { body }`. Saga 12 step 007.
65	    /// Name must be a string literal; anything else is a parse
66	    /// error to keep the grammar unambiguous.
67	    pub(crate) fn parse_experiment(&mut self) -> Result<Expr, ParseError> {
68	        let start = self.tokens[self.pos].span;
69	        self.pos += 1; // skip 'experiment'
70	        let tok = &self.tokens[self.pos];
71	        let TokenKind::StrLit(name) = &tok.kind else {
72	            return Err(ParseError::UnexpectedToken {
73	                found: describe_kind(&tok.kind),
74	                span: tok.span,
75	            });
76	        };
77	        let name = name.clone();
78	        self.pos += 1;
79	        let (body, end) = self.parse_braced_body()?;
80	        Ok(Expr::Experiment {
81	            name,
82	            body,
83	            span: Span::new(start.start, end.end),
84	        })
85	    }
86	
87	    /// Parse `for <ident> in <expr> { body }`. Saga 12 step 003.
88	    pub(crate) fn parse_for(&mut self) -> Result<Expr, ParseError> {
89	        let start = self.tokens[self.pos].span;
90	        self.pos += 1; // skip 'for'
91	        let tok = &self.tokens[self.pos];
92	        let TokenKind::Ident(binding) = &tok.kind else {
93	            return Err(ParseError::UnexpectedToken {
94	                found: describe_kind(&tok.kind),
95	                span: tok.span,
96	            });
97	        };
98	        let binding = binding.clone();
99	        self.pos += 1;
100	        self.expect(&TokenKind::In)?;
101	        let source = self.parse_expr(0)?;
102	        let (body, end) = self.parse_braced_body()?;
103	        Ok(Expr::For {
104	            binding,
105	            source: Box::new(source),
106	            body,
107	            span: Span::new(start.start, end.end),
108	        })
109	    }
110	
111	    /// Consume `{ stmt? (sep stmt)* }` and return the parsed body
112	    /// plus the closing brace's span. Shared by `parse_repeat`
113	    /// (which also handles `train`) and `parse_for`.
114	    pub(crate) fn parse_braced_body(&mut self) -> Result<(Vec<Expr>, Span), ParseError> {
115	        let open = self.expect(&TokenKind::LBrace)?;
116	        self.skip_sep();
117	        let mut body = Vec::new();
118	        while self.pos < self.tokens.len()
119	            && !self.is(TokenKind::RBrace)
120	            && self.tokens[self.pos].kind != TokenKind::Eof
121	        {
122	            body.push(self.parse_statement()?);
123	            self.skip_sep();
124	        }
125	        if !self.is(TokenKind::RBrace) {
126	            return Err(ParseError::UnclosedDelimiter {
127	                open: "{".into(),
128	                span: open,
129	            });
130	        }
131	        let end = self.tokens[self.pos].span;
132	        self.pos += 1;
133	        Ok((body, end))
134	    }
135	}
