//! Statement-shaped parser methods split out of `parser.rs` so that
//! module stays under the sw-checklist function-count budget.
//!
//! Every method here takes `&mut Parser` as the receiver via an
//! inherent-impl extension block. Saga 12 step 003 extraction
//! point.

use mlpl_core::Span;

use crate::ast::Expr;
use crate::error::{ParseError, describe_kind};
use crate::parser::Parser;
use crate::token::TokenKind;

impl Parser<'_> {
    /// Parse `name : [axis1, axis2, ...] = value` and desugar to
    /// `Assign { name, value: FnCall("label", [value, ArrayLit([StrLit(a1), ...])]) }`.
    /// Saga 11.5 Phase 2. An empty list `[]` is legal and means
    /// "scalar with no axes".
    pub(crate) fn parse_annotated_assign(&mut self) -> Result<Expr, ParseError> {
        let start = self.tokens[self.pos].span;
        let TokenKind::Ident(n) = &self.tokens[self.pos].kind else {
            unreachable!()
        };
        let name = n.clone();
        self.pos += 2; // skip name and ':'
        let br_start = self.expect(&TokenKind::LBracket)?;
        let mut labels: Vec<Expr> = Vec::new();
        while !self.is(TokenKind::RBracket) {
            let tok = &self.tokens[self.pos];
            let TokenKind::Ident(a) = &tok.kind else {
                return Err(ParseError::UnexpectedToken {
                    found: describe_kind(&tok.kind),
                    span: tok.span,
                });
            };
            labels.push(Expr::StrLit(a.clone(), tok.span));
            self.pos += 1;
            if self.is(TokenKind::Comma) {
                self.pos += 1;
            } else {
                break;
            }
        }
        let br_end = self.expect(&TokenKind::RBracket)?;
        self.expect(&TokenKind::Equals)?;
        let value = self.parse_expr(0)?;
        let value_span = value.span();
        let call = Expr::FnCall {
            name: "label".into(),
            args: vec![
                value,
                Expr::ArrayLit(labels, Span::new(br_start.start, br_end.end)),
            ],
            span: Span::new(br_start.start, value_span.end),
        };
        Ok(Expr::Assign {
            name,
            value: Box::new(call),
            span: Span::new(start.start, value_span.end),
        })
    }

    /// Parse `experiment "name" { body }`. Saga 12 step 007.
    /// Name must be a string literal; anything else is a parse
    /// error to keep the grammar unambiguous.
    pub(crate) fn parse_experiment(&mut self) -> Result<Expr, ParseError> {
        let start = self.tokens[self.pos].span;
        self.pos += 1; // skip 'experiment'
        let tok = &self.tokens[self.pos];
        let TokenKind::StrLit(name) = &tok.kind else {
            return Err(ParseError::UnexpectedToken {
                found: describe_kind(&tok.kind),
                span: tok.span,
            });
        };
        let name = name.clone();
        self.pos += 1;
        let (body, end) = self.parse_braced_body()?;
        Ok(Expr::Experiment {
            name,
            body,
            span: Span::new(start.start, end.end),
        })
    }

    /// Parse `for <ident> in <expr> { body }`. Saga 12 step 003.
    pub(crate) fn parse_for(&mut self) -> Result<Expr, ParseError> {
        let start = self.tokens[self.pos].span;
        self.pos += 1; // skip 'for'
        let tok = &self.tokens[self.pos];
        let TokenKind::Ident(binding) = &tok.kind else {
            return Err(ParseError::UnexpectedToken {
                found: describe_kind(&tok.kind),
                span: tok.span,
            });
        };
        let binding = binding.clone();
        self.pos += 1;
        self.expect(&TokenKind::In)?;
        let source = self.parse_expr(0)?;
        let (body, end) = self.parse_braced_body()?;
        Ok(Expr::For {
            binding,
            source: Box::new(source),
            body,
            span: Span::new(start.start, end.end),
        })
    }

    /// Consume `{ stmt? (sep stmt)* }` and return the parsed body
    /// plus the closing brace's span. Shared by `parse_repeat`
    /// (which also handles `train`) and `parse_for`.
    pub(crate) fn parse_braced_body(&mut self) -> Result<(Vec<Expr>, Span), ParseError> {
        let open = self.expect(&TokenKind::LBrace)?;
        self.skip_sep();
        let mut body = Vec::new();
        while self.pos < self.tokens.len()
            && !self.is(TokenKind::RBrace)
            && self.tokens[self.pos].kind != TokenKind::Eof
        {
            body.push(self.parse_statement()?);
            self.skip_sep();
        }
        if !self.is(TokenKind::RBrace) {
            return Err(ParseError::UnclosedDelimiter {
                open: "{".into(),
                span: open,
            });
        }
        let end = self.tokens[self.pos].span;
        self.pos += 1;
        Ok((body, end))
    }
}

//! AST node types for MLPL.
//!
//! These are parser-owned syntax nodes. They do NOT depend on mlpl-array.

use mlpl_core::Span;

/// Binary operator kind.
#[derive(Clone, Debug, PartialEq)]
pub enum BinOpKind {
    /// `+`
    Add,
    /// `-`
    Sub,
    /// `*`
    Mul,
    /// `/`
    Div,
}

/// Kind of tensor constructor: trainable parameter or non-trainable tensor.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TensorCtorKind {
    /// `param[shape]` -- trainable leaf (`requires_grad` = true).
    Param,
    /// `tensor[shape]` -- non-trainable leaf.
    Tensor,
}

/// An expression in the MLPL AST.
#[derive(Clone, Debug, PartialEq)]
pub enum Expr {
    /// Integer literal.
    IntLit(i64, Span),
    /// Float literal.
    FloatLit(f64, Span),
    /// String literal.
    StrLit(String, Span),
    /// Identifier reference.
    Ident(String, Span),
    /// Array literal: `[expr, expr, ...]`
    ArrayLit(Vec<Expr>, Span),
    /// Binary operation: `lhs op rhs`
    BinOp {
        /// The operator.
        op: BinOpKind,
        /// Left-hand side.
        lhs: Box<Expr>,
        /// Right-hand side.
        rhs: Box<Expr>,
        /// Span covering the full expression.
        span: Span,
    },
    /// Function call: `name(args...)`
    FnCall {
        /// Function name.
        name: String,
        /// Arguments.
        args: Vec<Expr>,
        /// Span covering name through closing paren.
        span: Span,
    },
    /// Unary negation: `-expr`
    UnaryNeg {
        /// The operand.
        operand: Box<Expr>,
        /// Span covering the minus through the operand.
        span: Span,
    },
    /// Assignment: `name = value`
    Assign {
        /// Variable name.
        name: String,
        /// Value expression.
        value: Box<Expr>,
        /// Span covering name through value.
        span: Span,
    },
    /// Tensor constructor: `param[shape...]` or `tensor[shape...]`.
    TensorCtor {
        /// Which kind of leaf to construct.
        kind: TensorCtorKind,
        /// Shape dimension expressions.
        shape: Vec<Expr>,
        /// Span covering keyword through closing bracket.
        span: Span,
    },
    /// Repeat loop: `repeat <count> { body }`
    Repeat {
        /// Number of iterations.
        count: Box<Expr>,
        /// Body statements.
        body: Vec<Expr>,
        /// Span covering keyword through closing brace.
        span: Span,
    },
    /// Training loop: `train <count> { body }`. On each iteration the
    /// loop binds the iteration index to `step`, runs the body, and
    /// captures the value of the body's final statement as the
    /// per-step loss. After the loop, all captured losses are stored
    /// in the environment as a 1-D array under the name `last_losses`.
    Train {
        /// Number of training steps.
        count: Box<Expr>,
        /// Body statements; the value of the last one is the loss.
        body: Vec<Expr>,
        /// Span covering keyword through closing brace.
        span: Span,
    },
    /// Scoped experiment block: `experiment "name" { body }`
    /// (Saga 12 step 007). Runs body in the current environment;
    /// on exit, scans `_metric`-suffixed scalar vars and appends a
    /// record to `env.experiment_log`. When the environment has an
    /// `exp_dir` set (terminal REPL only), also writes a
    /// `run.json` record to disk.
    Experiment {
        /// Human-chosen name for the run; used in file paths.
        name: String,
        /// Body statements.
        body: Vec<Expr>,
        /// Span covering the keyword through the closing brace.
        span: Span,
    },
    /// Streaming iteration: `for <binding> in <source> { body }`
    /// (Saga 12 step 003). On each iteration binds `binding` to a
    /// rank-(r-1) slice of `source`'s axis 0. After the loop, each
    /// iteration's final value is captured into `last_rows` in the
    /// environment (mirrors `Train`'s `last_losses`).
    For {
        /// Name to bind to each row slice.
        binding: String,
        /// Source expression (must have rank >= 1).
        source: Box<Expr>,
        /// Body statements.
        body: Vec<Expr>,
        /// Span covering keyword through closing brace.
        span: Span,
    },
}

impl Expr {
    /// Return the source span for this expression.
    #[must_use]
    pub fn span(&self) -> Span {
        match self {
            Self::IntLit(_, s)
            | Self::FloatLit(_, s)
            | Self::StrLit(_, s)
            | Self::Ident(_, s)
            | Self::ArrayLit(_, s)
            | Self::BinOp { span: s, .. }
            | Self::UnaryNeg { span: s, .. }
            | Self::FnCall { span: s, .. }
            | Self::Assign { span: s, .. }
            | Self::TensorCtor { span: s, .. }
            | Self::Repeat { span: s, .. }
            | Self::Train { span: s, .. }
            | Self::For { span: s, .. }
            | Self::Experiment { span: s, .. } => *s,
        }
    }
}

