21	pub(crate) struct Parser<'a> {
22	    pub(crate) tokens: &'a [Token],
23	    pub(crate) pos: usize,
24	}
25	
26	impl<'a> Parser<'a> {
27	    /// Parse a single statement (assignment, repeat, or expression).
28	    pub(crate) fn parse_statement(&mut self) -> Result<Expr, ParseError> {
29	        if self.tokens[self.pos].kind == TokenKind::Repeat {
30	            return self.parse_repeat(false);
31	        }
32	        if self.tokens[self.pos].kind == TokenKind::Train {
33	            return self.parse_repeat(true);
34	        }
35	        if self.tokens[self.pos].kind == TokenKind::For {
36	            return self.parse_for();
37	        }
38	        if self.tokens[self.pos].kind == TokenKind::Experiment {
39	            return self.parse_experiment();
40	        }
41	        if matches!(self.tokens[self.pos].kind, TokenKind::Ident(_))
42	            && self
43	                .tokens
44	                .get(self.pos + 1)
45	                .is_some_and(|t| t.kind == TokenKind::Equals)
46	        {
47	            let name_tok = &self.tokens[self.pos];
48	            let name = match &name_tok.kind {
49	                TokenKind::Ident(n) => n.clone(),
50	                _ => unreachable!(),
51	            };
52	            let start = name_tok.span;
53	            self.pos += 2;
54	            let value = self.parse_expr(0)?;
55	            let span = Span::new(start.start, value.span().end);
56	            return Ok(Expr::Assign {
57	                name,
58	                value: Box::new(value),
59	                span,
60	            });
61	        }
62	        if matches!(self.tokens[self.pos].kind, TokenKind::Ident(_))
63	            && self
64	                .tokens
65	                .get(self.pos + 1)
66	                .is_some_and(|t| t.kind == TokenKind::Colon)
67	        {
68	            return self.parse_annotated_assign();
69	        }
70	        self.parse_expr(0)
71	    }
72	
73	    /// Consume a token of the given kind or return `UnexpectedToken`.
74	    /// Returns the consumed token's span on success.
75	    pub(crate) fn expect(&mut self, kind: &TokenKind) -> Result<Span, ParseError> {
76	        if std::mem::discriminant(&self.tokens[self.pos].kind) == std::mem::discriminant(kind) {
77	            let span = self.tokens[self.pos].span;
78	            self.pos += 1;
79	            Ok(span)
80	        } else {
81	            Err(ParseError::UnexpectedToken {
82	                found: describe_kind(&self.tokens[self.pos].kind),
83	                span: self.tokens[self.pos].span,
84	            })
85	        }
86	    }
87	
88	    /// Parse an expression with precedence climbing (min_prec=0 for full expr).
89	    pub(crate) fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, ParseError> {
90	        let mut lhs = self.parse_atom()?;
91	        loop {
92	            let Some((op, prec)) = self.tokens.get(self.pos).and_then(|t| match t.kind {
93	                TokenKind::Plus => Some((BinOpKind::Add, 1u8)),
94	                TokenKind::Minus => Some((BinOpKind::Sub, 1)),
95	                TokenKind::Star => Some((BinOpKind::Mul, 2)),
96	                TokenKind::Slash => Some((BinOpKind::Div, 2)),
97	                _ => None,
98	            }) else {
99	                break;
100	            };
101	            if prec < min_prec {
102	                break;
103	            }
104	            self.pos += 1;
105	            let rhs = self.parse_expr(prec + 1)?;
106	            let span = Span::new(lhs.span().start, rhs.span().end);
107	            lhs = Expr::BinOp {
108	                op,
109	                lhs: Box::new(lhs),
110	                rhs: Box::new(rhs),
111	                span,
112	            };
113	        }
114	        Ok(lhs)
115	    }
116	
117	    pub(crate) fn parse_atom(&mut self) -> Result<Expr, ParseError> {
118	        let tok = &self.tokens[self.pos];
119	        match &tok.kind {
120	            TokenKind::Minus => {
121	                let start = tok.span;
122	                self.pos += 1;
123	                let operand = self.parse_atom()?;
124	                let span = Span::new(start.start, operand.span().end);
125	                Ok(Expr::UnaryNeg {
126	                    operand: Box::new(operand),
127	                    span,
128	                })
129	            }
130	            TokenKind::IntLit(n) => {
131	                let e = Expr::IntLit(*n, tok.span);
132	                self.pos += 1;
133	                Ok(e)
134	            }
135	            TokenKind::FloatLit(f) => {
136	                let e = Expr::FloatLit(*f, tok.span);
137	                self.pos += 1;
138	                Ok(e)
139	            }
140	            TokenKind::StrLit(s) => {
141	                let e = Expr::StrLit(s.clone(), tok.span);
142	                self.pos += 1;
143	                Ok(e)
144	            }
145	            TokenKind::Ident(name) => {
146	                let name = name.clone();
147	                let start = tok.span;
148	                self.pos += 1;
149	                // Tensor constructor: `param[...]` or `tensor[...]`
150	                if self.is(TokenKind::LBracket) {
151	                    let ctor_kind = match name.as_str() {
152	                        "param" => Some(TensorCtorKind::Param),
153	                        "tensor" => Some(TensorCtorKind::Tensor),
154	                        _ => None,
155	                    };
156	                    if let Some(kind) = ctor_kind {
157	                        return self.parse_tensor_ctor(kind, start);
158	                    }
159	                }
160	                // Function call: ident '('
161	                if self.is(TokenKind::LParen) {
162	                    self.pos += 1; // skip '('
163	                    let mut args = Vec::new();
164	                    if !self.is(TokenKind::RParen) {
165	                        args.push(self.parse_expr(0)?);
166	                        while self.is(TokenKind::Comma) {
167	                            self.pos += 1;
168	                            args.push(self.parse_expr(0)?);
169	                        }
170	                    }
171	                    if !self.is(TokenKind::RParen) {
172	                        return Err(ParseError::UnclosedDelimiter {
173	                            open: "(".into(),
174	                            span: start,
175	                        });
176	                    }
177	                    let end = self.tokens[self.pos].span;
178	                    self.pos += 1;
179	                    Ok(Expr::FnCall {
180	                        name,
181	                        args,
182	                        span: Span::new(start.start, end.end),
183	                    })
184	                } else {
185	                    Ok(Expr::Ident(name, start))
186	                }
187	            }
188	            TokenKind::LBracket => self.parse_array_lit(),
189	            TokenKind::LParen => {
190	                let open = tok.span;
191	                self.pos += 1;
192	                let expr = self.parse_expr(0)?;
193	                if !self.is(TokenKind::RParen) {
194	                    return Err(ParseError::UnclosedDelimiter {
195	                        open: "(".into(),
196	                        span: open,
197	                    });
198	                }
199	                self.pos += 1;
200	                Ok(expr)
201	            }
202	            _ => Err(ParseError::UnexpectedToken {
203	                found: describe_kind(&tok.kind),
204	                span: tok.span,
205	            }),
206	        }
207	    }
208	
209	    fn parse_tensor_ctor(&mut self, kind: TensorCtorKind, start: Span) -> Result<Expr, ParseError> {
210	        let open_span = self.tokens[self.pos].span;
211	        self.pos += 1; // skip '['
212	        let mut shape = Vec::new();
213	        if !self.is(TokenKind::RBracket) {
214	            shape.push(self.parse_expr(0)?);
215	            while self.is(TokenKind::Comma) {
216	                self.pos += 1;
217	                shape.push(self.parse_expr(0)?);
218	            }
219	        }
220	        if !self.is(TokenKind::RBracket) {
221	            return Err(ParseError::UnclosedDelimiter {
222	                open: "[".into(),
223	                span: open_span,
224	            });
225	        }
226	        let close_span = self.tokens[self.pos].span;
227	        self.pos += 1;
228	        Ok(Expr::TensorCtor {
229	            kind,
230	            shape,
231	            span: Span::new(start.start, close_span.end),
232	        })
233	    }
234	
235	    fn parse_array_lit(&mut self) -> Result<Expr, ParseError> {
236	        let open_span = self.tokens[self.pos].span;
237	        self.pos += 1;
238	        let mut elems = Vec::new();
239	        if !self.is(TokenKind::RBracket) {
240	            elems.push(self.parse_expr(0)?);
241	            while self.is(TokenKind::Comma) {
242	                self.pos += 1;
243	                elems.push(self.parse_expr(0)?);
244	            }
245	        }
246	        if !self.is(TokenKind::RBracket) {
247	            return Err(ParseError::UnclosedDelimiter {
248	                open: "[".into(),
249	                span: open_span,
250	            });
251	        }
252	        let close_span = self.tokens[self.pos].span;
253	        self.pos += 1;
254	        Ok(Expr::ArrayLit(
255	            elems,
256	            Span::new(open_span.start, close_span.end),
257	        ))
258	    }
259	
260	    fn parse_repeat(&mut self, is_train: bool) -> Result<Expr, ParseError> {
261	        let start = self.tokens[self.pos].span;
262	        self.pos += 1; // skip 'repeat' or 'train'
263	        let count = self.parse_expr(0)?;
264	        let (body, end) = self.parse_braced_body()?;
265	        let span = Span::new(start.start, end.end);
266	        let count = Box::new(count);
267	        Ok(if is_train {
268	            Expr::Train { count, body, span }
269	        } else {
270	            Expr::Repeat { count, body, span }
271	        })
272	    }
273	
274	    pub(crate) fn is(&self, kind: TokenKind) -> bool {
275	        self.pos < self.tokens.len()
276	            && std::mem::discriminant(&self.tokens[self.pos].kind) == std::mem::discriminant(&kind)
277	    }
278	
279	    pub(crate) fn skip_sep(&mut self) {
280	        while self.pos < self.tokens.len()
281	            && matches!(
282	                self.tokens[self.pos].kind,
283	                TokenKind::Newline | TokenKind::Semicolon
284	            )
285	        {
286	            self.pos += 1;
287	        }
288	    }
289	}
