1	//! Evaluation environment (variable bindings).
2	
3	use std::collections::{HashMap, HashSet};
4	use std::path::PathBuf;
5	
6	use mlpl_array::DenseArray;
7	
8	use crate::experiment::ExperimentRecord;
9	use crate::grad::OptimizerState;
10	use crate::model::ModelSpec;
11	use crate::tokenizer::TokenizerSpec;
12	
13	/// Variable bindings for evaluation.
14	#[derive(Clone, Debug, Default)]
15	pub struct Environment {
16	    pub(crate) vars: HashMap<String, DenseArray>,
17	    pub(crate) params: HashSet<String>,
18	    pub(crate) optim_state: OptimizerState,
19	    pub(crate) models: HashMap<String, ModelSpec>,
20	    pub(crate) next_model_id: u64,
21	    /// Tokenizer bindings (Saga 12 step 004). Sibling to `models`.
22	    pub(crate) tokenizers: HashMap<String, TokenizerSpec>,
23	    /// Sandbox root for filesystem `load("relative-path")` calls.
24	    /// `None` means filesystem access is disabled (the web REPL
25	    /// surface, where `std::fs` doesn't exist under WASM). Saga 12
26	    /// step 001.
27	    pub(crate) data_dir: Option<PathBuf>,
28	    /// String-valued variable bindings (Saga 12 step 009). Sibling
29	    /// to `vars`; populated when assignment value is a `Value::Str`
30	    /// (e.g. `corpus = load_preloaded("...")`). Ident lookup checks
31	    /// here before falling through to array vars.
32	    pub(crate) strings: HashMap<String, String>,
33	    /// Output directory for `experiment` records. `None` disables
34	    /// disk writes (web REPL); `Some(path)` is set by the terminal
35	    /// REPL's `--exp-dir` flag. Saga 12 step 007.
36	    pub(crate) exp_dir: Option<PathBuf>,
37	    /// Append-only log of completed experiments in this env.
38	    pub(crate) experiment_log: Vec<ExperimentRecord>,
39	}
40	
41	impl Environment {
42	    /// Create an empty environment.
43	    #[must_use]
44	    pub fn new() -> Self {
45	        Self::default()
46	    }
47	
48	    /// Look up a variable by name.
49	    pub fn get(&self, name: &str) -> Option<&DenseArray> {
50	        self.vars.get(name)
51	    }
52	
53	    /// Set a variable binding.
54	    pub fn set(&mut self, name: String, value: DenseArray) {
55	        self.vars.insert(name, value);
56	    }
57	
58	    /// Set a variable and mark it as a trainable parameter (tracked by `grad`).
59	    pub fn set_param(&mut self, name: String, value: DenseArray) {
60	        self.params.insert(name.clone());
61	        self.vars.insert(name, value);
62	    }
63	
64	    /// Mark an existing variable as a trainable parameter.
65	    pub fn mark_param(&mut self, name: &str) {
66	        self.params.insert(name.to_string());
67	    }
68	
69	    /// Whether `name` is a trainable parameter in this environment.
70	    #[must_use]
71	    pub fn is_param(&self, name: &str) -> bool {
72	        self.params.contains(name)
73	    }
74	
75	    /// Iterate over all (name, value) parameter bindings.
76	    pub fn params(&self) -> impl Iterator<Item = (&String, &DenseArray)> {
77	        self.params
78	            .iter()
79	            .filter_map(move |n| self.vars.get(n).map(|v| (n, v)))
80	    }
81	
82	    /// Look up a model by name (Saga 11). Returns `None` if `name`
83	    /// is not bound to a model value.
84	    #[must_use]
85	    pub fn get_model(&self, name: &str) -> Option<&ModelSpec> {
86	        self.models.get(name)
87	    }
88	
89	    /// Set the sandbox root for `load("relative-path")` (Saga 12
90	    /// step 001). The terminal REPL calls this from a `--data-dir`
91	    /// CLI flag; the web REPL never calls this, leaving fs access
92	    /// disabled.
93	    pub fn set_data_dir(&mut self, dir: PathBuf) {
94	        self.data_dir = Some(dir);
95	    }
96	
97	    /// Bind `name` to a tokenizer value. Saga 12 step 004.
98	    pub fn set_tokenizer(&mut self, name: String, tok: TokenizerSpec) {
99	        self.tokenizers.insert(name, tok);
100	    }
101	
102	    /// Look up a tokenizer by name. Returns `None` if `name` is
103	    /// not bound to a tokenizer.
104	    #[must_use]
105	    pub fn get_tokenizer(&self, name: &str) -> Option<&TokenizerSpec> {
106	        self.tokenizers.get(name)
107	    }
108	
109	    /// Borrow the current sandbox root, if any.
110	    #[must_use]
111	    pub fn data_dir(&self) -> Option<&PathBuf> {
112	        self.data_dir.as_ref()
113	    }
114	
115	    /// Set the output directory for `experiment` records. Saga 12
116	    /// step 007. The terminal REPL calls this from a `--exp-dir`
117	    /// CLI flag; the web REPL leaves it unset so nothing is
118	    /// written to disk.
119	    pub fn set_exp_dir(&mut self, dir: PathBuf) {
120	        self.exp_dir = Some(dir);
121	    }
122	
123	    /// Borrow the configured experiment output dir, if any.
124	    #[must_use]
125	    pub fn exp_dir(&self) -> Option<&PathBuf> {
126	        self.exp_dir.as_ref()
127	    }
128	
129	    /// Append a completed experiment record to the log.
130	    pub fn push_experiment_log(&mut self, rec: ExperimentRecord) {
131	        self.experiment_log.push(rec);
132	    }
133	
134	    /// Borrow every recorded experiment in order.
135	    #[must_use]
136	    pub fn experiment_log(&self) -> &[ExperimentRecord] {
137	        &self.experiment_log
138	    }
139	
140	    /// Iterate over every bound `(name, DenseArray)`. Used by
141	    /// `experiment` to scan for `_metric`-suffixed scalars.
142	    pub fn vars_iter(&self) -> impl Iterator<Item = (&String, &DenseArray)> {
143	        self.vars.iter()
144	    }
145	
146	    /// Bind a string value to `name`. Saga 12 step 009.
147	    pub fn set_string(&mut self, name: String, value: String) {
148	        self.strings.insert(name, value);
149	    }
150	
151	    /// Look up a string binding by name.
152	    #[must_use]
153	    pub fn get_string(&self, name: &str) -> Option<&String> {
154	        self.strings.get(name)
155	    }
156	}
