1	//! `experiment "name" { body }` evaluator + record type
2	//! (Saga 12 step 007) and the registry readers used by
3	//! `:experiments` / `compare()` (Saga 12 step 008).
4	
5	use std::collections::BTreeMap;
6	use std::path::Path;
7	
8	use mlpl_array::DenseArray;
9	use mlpl_parser::Expr;
10	use mlpl_trace::{Trace, TraceValue};
11	use serde::{Deserialize, Serialize};
12	
13	use crate::env::Environment;
14	use crate::error::EvalError;
15	
16	/// One recorded run. Written to `<exp_dir>/<name>/<ts>/run.json`
17	/// by the terminal REPL; also appended to `env.experiment_log`
18	/// so the web REPL can surface runs via `:experiments`.
19	#[derive(Clone, Debug, Serialize, Deserialize)]
20	pub struct ExperimentRecord {
21	    /// Name passed to the `experiment "..."` form.
22	    pub name: String,
23	    /// Wall-clock `SystemTime::duration_since(UNIX_EPOCH)` in
24	    /// nanoseconds at run-entry. Used to make the on-disk
25	    /// timestamp subdir unique.
26	    pub timestamp_ns: u128,
27	    /// `_metric`-suffixed scalar values captured at run-exit.
28	    pub metrics: BTreeMap<String, f64>,
29	    /// Shape metadata for every bound tracked parameter at
30	    /// run-exit. Keyed by param name.
31	    pub params_snapshot: BTreeMap<String, ParamShape>,
32	}
33	
34	/// Shape snapshot stored inside an `ExperimentRecord`.
35	#[derive(Clone, Debug, Serialize, Deserialize)]
36	pub struct ParamShape {
37	    /// Positional dims.
38	    pub shape: Vec<usize>,
39	    /// Per-axis labels when the array is labeled; `None` when
40	    /// the array has no labels.
41	    pub labels: Option<Vec<Option<String>>>,
42	}
43	
44	/// Evaluate an `experiment "name" { body }` block.
45	pub(crate) fn eval_experiment(
46	    name: &str,
47	    body: &[Expr],
48	    env: &mut Environment,
49	    trace: &mut Option<&mut Trace>,
50	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
51	    let timestamp_ns = experiment_timestamp_ns();
52	    let mut last = DenseArray::from_scalar(0.0);
53	    for stmt in body {
54	        last = crate::eval::eval_expr(stmt, env, trace)?.into_array()?;
55	    }
56	    let metrics = collect_metrics(env);
57	    let params_snapshot = collect_param_shapes(env);
58	    let record = ExperimentRecord {
59	        name: name.to_string(),
60	        timestamp_ns,
61	        metrics,
62	        params_snapshot,
63	    };
64	    if let Some(dir) = env.exp_dir().cloned() {
65	        write_record_to_disk(&dir, &record)
66	            .map_err(|e| EvalError::Unsupported(format!("experiment: {e}")))?;
67	    }
68	    env.push_experiment_log(record);
69	    Ok(("experiment", vec![], last))
70	}
71	
72	/// Per-run timestamp used to make on-disk run dirs unique and to
73	/// sort the registry. `wasm32-unknown-unknown` has no real clock
74	/// (SystemTime::now() panics), so on that target we fall back to a
75	/// monotonic in-process counter, which is sufficient for ordering
76	/// runs captured in `env.experiment_log` even though the resulting
77	/// value is not wall-clock time.
78	#[cfg(not(target_arch = "wasm32"))]
79	fn experiment_timestamp_ns() -> u128 {
80	    std::time::SystemTime::now()
81	        .duration_since(std::time::UNIX_EPOCH)
82	        .map(|d| d.as_nanos())
83	        .unwrap_or(0)
84	}
85	
86	#[cfg(target_arch = "wasm32")]
87	fn experiment_timestamp_ns() -> u128 {
88	    use std::sync::atomic::{AtomicU64, Ordering};
89	    static COUNTER: AtomicU64 = AtomicU64::new(1);
90	    COUNTER.fetch_add(1, Ordering::Relaxed) as u128
91	}
92	
93	fn collect_metrics(env: &Environment) -> BTreeMap<String, f64> {
94	    let mut out = BTreeMap::new();
95	    for (name, arr) in env.vars_iter() {
96	        if name.ends_with("_metric") && arr.rank() == 0 {
97	            out.insert(name.clone(), arr.data()[0]);
98	        }
99	    }
100	    out
101	}
102	
103	fn collect_param_shapes(env: &Environment) -> BTreeMap<String, ParamShape> {
104	    let mut out = BTreeMap::new();
105	    for (name, arr) in env.params() {
106	        out.insert(
107	            name.clone(),
108	            ParamShape {
109	                shape: arr.shape().dims().to_vec(),
110	                labels: arr.labels().map(<[_]>::to_vec),
111	            },
112	        );
113	    }
114	    out
115	}
116	
117	fn write_record_to_disk(dir: &Path, rec: &ExperimentRecord) -> Result<(), String> {
118	    let run_dir = dir.join(&rec.name).join(rec.timestamp_ns.to_string());
119	    std::fs::create_dir_all(&run_dir)
120	        .map_err(|e| format!("creating {}: {e}", run_dir.display()))?;
121	    let json = serde_json::to_string_pretty(rec).map_err(|e| format!("serializing record: {e}"))?;
122	    std::fs::write(run_dir.join("run.json"), json).map_err(|e| format!("writing run.json: {e}"))?;
123	    Ok(())
124	}
125	
126	/// Walk `<exp_dir>/*/*/run.json` and return every record that
127	/// deserializes cleanly. Malformed `run.json` files are skipped
128	/// silently -- a future step can wire up a warning channel.
129	pub(crate) fn read_records_from_disk(dir: &Path) -> Vec<ExperimentRecord> {
130	    let mut out = Vec::new();
131	    let Ok(name_dirs) = std::fs::read_dir(dir) else {
132	        return out;
133	    };
134	    for name_entry in name_dirs.flatten() {
135	        let Ok(ts_dirs) = std::fs::read_dir(name_entry.path()) else {
136	            continue;
137	        };
138	        for ts_entry in ts_dirs.flatten() {
139	            let run_json = ts_entry.path().join("run.json");
140	            let Ok(body) = std::fs::read_to_string(&run_json) else {
141	                continue;
142	            };
143	            if let Ok(rec) = serde_json::from_str::<ExperimentRecord>(&body) {
144	                out.push(rec);
145	            }
146	        }
147	    }
148	    out
149	}
150	
151	/// Produce the `:experiments` REPL output: merges
152	/// `env.experiment_log` (memory) with any on-disk records under
153	/// `env.exp_dir`, sorts by `timestamp_ns`, and prints one line per
154	/// run with name, timestamp, and top-line metric. Saga 12 step 008.
155	pub fn format_registry(env: &crate::env::Environment) -> String {
156	    let mut all: Vec<ExperimentRecord> = env.experiment_log().to_vec();
157	    if let Some(dir) = env.exp_dir() {
158	        all.extend(read_records_from_disk(dir));
159	    }
160	    if all.is_empty() {
161	        return "(no experiments recorded)".into();
162	    }
163	    all.sort_by_key(|r| r.timestamp_ns);
164	    let mut out = String::new();
165	    for r in &all {
166	        let summary = r
167	            .metrics
168	            .iter()
169	            .next()
170	            .map_or("(no metrics)".to_string(), |(k, v)| format!("{k}={v}"));
171	        out.push_str(&format!("  {} @ {} -- {summary}\n", r.name, r.timestamp_ns));
172	    }
173	    out.truncate(out.trim_end().len());
174	    out
175	}
176	
177	/// `compare(name_a, name_b)` builtin dispatch. Returns a
178	/// `Value::Str` containing a side-by-side of the most recent
179	/// runs with each name. Errors if either name has no records or
180	/// args are malformed.
181	pub(crate) fn dispatch_compare(
182	    args: &[Expr],
183	    env: &mut crate::env::Environment,
184	) -> Result<crate::value::Value, crate::error::EvalError> {
185	    if args.len() != 2 {
186	        return Err(crate::error::EvalError::BadArity {
187	            func: "compare".into(),
188	            expected: 2,
189	            got: args.len(),
190	        });
191	    }
192	    let Expr::StrLit(a, _) = &args[0] else {
193	        return Err(crate::error::EvalError::Unsupported(
194	            "compare: arguments must be string literals".into(),
195	        ));
196	    };
197	    let Expr::StrLit(b, _) = &args[1] else {
198	        return Err(crate::error::EvalError::Unsupported(
199	            "compare: arguments must be string literals".into(),
200	        ));
201	    };
202	    let ra = latest_by_name(env, a).ok_or_else(|| {
203	        crate::error::EvalError::Unsupported(format!("compare: no run named {a:?}"))
204	    })?;
205	    let rb = latest_by_name(env, b).ok_or_else(|| {
206	        crate::error::EvalError::Unsupported(format!("compare: no run named {b:?}"))
207	    })?;
208	    Ok(crate::value::Value::Str(render_compare(&ra, &rb)))
209	}
210	
211	fn latest_by_name(env: &crate::env::Environment, name: &str) -> Option<ExperimentRecord> {
212	    let mut all: Vec<ExperimentRecord> = env.experiment_log().to_vec();
213	    if let Some(dir) = env.exp_dir() {
214	        all.extend(read_records_from_disk(dir));
215	    }
216	    all.into_iter()
217	        .filter(|r| r.name == name)
218	        .max_by_key(|r| r.timestamp_ns)
219	}
220	
221	fn render_compare(a: &ExperimentRecord, b: &ExperimentRecord) -> String {
222	    let mut keys: std::collections::BTreeSet<String> = a.metrics.keys().cloned().collect();
223	    keys.extend(b.metrics.keys().cloned());
224	    if keys.is_empty() {
225	        return format!(
226	            "compare {} vs {} -- (no metrics on either run)",
227	            a.name, b.name
228	        );
229	    }
230	    let mut out = format!("compare {} vs {}\n", a.name, b.name);
231	    for k in &keys {
232	        let av = a.metrics.get(k).copied();
233	        let bv = b.metrics.get(k).copied();
234	        let delta = match (av, bv) {
235	            (Some(x), Some(y)) => format!(" (delta {:+})", y - x),
236	            _ => String::new(),
237	        };
238	        let a_fmt = av.map_or("-".to_string(), |v| v.to_string());
239	        let b_fmt = bv.map_or("-".to_string(), |v| v.to_string());
240	        out.push_str(&format!("  {k}: {a_fmt} vs {b_fmt}{delta}\n"));
241	    }
242	    out.truncate(out.trim_end().len());
243	    out
244	}
245

