//! Tests for the `experiment "name" { body }` scoped form
//! (Saga 12 step 007).
//!
//! Semantics: run body in the normal environment. On loop exit,
//! scan every bound scalar whose name ends in `_metric`,
//! snapshot `(name, value)` pairs and param shape metadata, and
//! append to `env.experiment_log`. When `env.exp_dir` is set
//! (terminal REPL via `--exp-dir`), also write a `run.json`
//! record; the web REPL leaves `exp_dir` unset.

use mlpl_eval::{Environment, ExperimentRecord, eval_program};
use mlpl_parser::{lex, parse};

fn run(src: &str, env: &mut Environment) {
    let tokens = lex(src).unwrap();
    let stmts = parse(&tokens).unwrap();
    let _ = eval_program(&stmts, env).unwrap();
}

fn run_expect_err(src: &str, env: &mut Environment) -> mlpl_eval::EvalError {
    let tokens = lex(src).unwrap();
    let stmts = parse(&tokens).unwrap();
    eval_program(&stmts, env).unwrap_err()
}

fn tempdir(tag: &str) -> std::path::PathBuf {
    let base = std::env::temp_dir();
    let pid = std::process::id();
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_nanos();
    let p = base.join(format!("mlpl-exp-{tag}-{pid}-{nanos}"));
    std::fs::create_dir_all(&p).unwrap();
    p
}

// -- Parser + language surface --

#[test]
fn parser_emits_experiment_variant() {
    use mlpl_parser::Expr;
    let stmts = parse(&lex("experiment \"test\" { x = 1 }").unwrap()).unwrap();
    assert_eq!(stmts.len(), 1);
    match &stmts[0] {
        Expr::Experiment { name, body, .. } => {
            assert_eq!(name, "test");
            assert_eq!(body.len(), 1);
        }
        other => panic!("expected Expr::Experiment, got {other:?}"),
    }
}

#[test]
fn experiment_empty_name_still_parses() {
    parse(&lex("experiment \"\" { x = 1 }").unwrap()).unwrap();
}

#[test]
fn experiment_missing_body_errors() {
    // `experiment "name"` with no brace block is a parse error.
    let r = parse(&lex("experiment \"name\"").unwrap());
    assert!(r.is_err());
}

// -- Evaluator: metric capture --

#[test]
fn experiment_appends_record_to_log() {
    let mut env = Environment::new();
    run("experiment \"first\" { x = 1 }", &mut env);
    let log: &[ExperimentRecord] = env.experiment_log();
    assert_eq!(log.len(), 1);
    assert_eq!(log[0].name, "first");
}

#[test]
fn experiment_captures_metric_suffixed_scalars() {
    let mut env = Environment::new();
    run(
        "experiment \"train\" { loss_metric = 0.25; accuracy_metric = 0.9 }",
        &mut env,
    );
    let rec = env.experiment_log().last().unwrap();
    let loss = rec.metrics.get("loss_metric").copied();
    let acc = rec.metrics.get("accuracy_metric").copied();
    assert_eq!(loss, Some(0.25));
    assert_eq!(acc, Some(0.9));
}

#[test]
fn experiment_ignores_non_metric_scalars() {
    let mut env = Environment::new();
    run(
        "experiment \"scan\" { lr = 0.01; loss_metric = 0.5 }",
        &mut env,
    );
    let rec = env.experiment_log().last().unwrap();
    assert!(rec.metrics.contains_key("loss_metric"));
    assert!(!rec.metrics.contains_key("lr"));

//! Token types for the MLPL lexer.

use mlpl_core::Span;

/// The kind of a lexer token.
#[derive(Clone, Debug, PartialEq)]
pub enum TokenKind {
    /// Integer literal.
    IntLit(i64),
    /// Float literal.
    FloatLit(f64),
    /// Identifier.
    Ident(String),
    /// String literal (double-quoted, escapes processed).
    StrLit(String),
    /// `(`
    LParen,
    /// `)`
    RParen,
    /// `[`
    LBracket,
    /// `]`
    RBracket,
    /// `,`
    Comma,
    /// `=`
    Equals,
    /// `:` (axis-label annotation, Saga 11.5 Phase 2).
    Colon,
    /// `;`
    Semicolon,
    /// `+`
    Plus,
    /// `-`
    Minus,
    /// `*`
    Star,
    /// `/`
    Slash,
    /// `{`
    LBrace,
    /// `}`
    RBrace,
    /// `repeat` keyword.
    Repeat,
    /// `train` keyword.
    Train,
    /// `for` keyword (streaming-iter, Saga 12 step 003).
    For,
    /// `in` keyword (only meaningful inside `for ... in ...`).
    In,
    /// `experiment` keyword (Saga 12 step 007).
    Experiment,
    /// Newline (statement separator).
    Newline,
    /// End of input.
    Eof,
}

/// A token with its source span.
#[derive(Clone, Debug, PartialEq)]
pub struct Token {
    /// What kind of token.
    pub kind: TokenKind,
    /// Where in the source.
    pub span: Span,
}

//! Error types for mlpl-parser.

use mlpl_core::Span;

use crate::token::TokenKind;

/// Render a `TokenKind` as the human-readable string used in
/// `ParseError::UnexpectedToken` messages. Lives in this module
/// because it is part of error surface formatting.
pub(crate) fn describe_kind(kind: &TokenKind) -> String {
    match kind {
        TokenKind::Eof => "end of input".into(),
        TokenKind::Newline => "newline".into(),
        TokenKind::IntLit(n) => format!("integer {n}"),
        TokenKind::FloatLit(n) => format!("float {n}"),
        TokenKind::StrLit(s) => format!("string \"{s}\""),
        TokenKind::Ident(s) => format!("identifier '{s}'"),
        TokenKind::LParen => "'('".into(),
        TokenKind::RParen => "')'".into(),
        TokenKind::LBracket => "'['".into(),
        TokenKind::RBracket => "']'".into(),
        TokenKind::LBrace => "'{'".into(),
        TokenKind::RBrace => "'}'".into(),
        TokenKind::Comma => "','".into(),
        TokenKind::Equals => "'='".into(),
        TokenKind::Colon => "':'".into(),
        TokenKind::Semicolon => "';'".into(),
        TokenKind::Plus => "'+'".into(),
        TokenKind::Minus => "'-'".into(),
        TokenKind::Star => "'*'".into(),
        TokenKind::Slash => "'/'".into(),
        TokenKind::Repeat => "'repeat'".into(),
        TokenKind::Train => "'train'".into(),
        TokenKind::For => "'for'".into(),
        TokenKind::In => "'in'".into(),
        TokenKind::Experiment => "'experiment'".into(),
    }
}

/// Errors produced during lexing and parsing.
#[derive(Clone, Debug, PartialEq)]
pub enum ParseError {
    /// An unexpected character was encountered during lexing.
    UnexpectedCharacter {
        /// The character.
        ch: char,
        /// Where it was found.
        span: Span,
    },
    /// A number literal could not be parsed.
    InvalidNumber {
        /// Where the number was.
        span: Span,
    },
    /// An unexpected token was encountered during parsing.
    UnexpectedToken {
        /// Description of what was found.
        found: String,
        /// Where it was found.
        span: Span,
    },
    /// Expected a closing delimiter that was not found.
    UnclosedDelimiter {
        /// The opening delimiter.
        open: String,
        /// Where the opening delimiter was.
        span: Span,
    },
    /// Bytes inside a string literal were not valid UTF-8. Saga 12.
    InvalidUtf8 {
        /// Byte span of the offending sequence.
        span: Span,
    },
}

impl std::fmt::Display for ParseError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::UnexpectedCharacter { ch, span } => {
                write!(f, "unexpected character '{ch}' at {span}")
            }
            Self::InvalidNumber { span } => write!(f, "invalid number at {span}"),
            Self::UnexpectedToken { found, span } => {
                write!(f, "unexpected token '{found}' at {span}")
            }
            Self::UnclosedDelimiter { open, span } => {
                write!(f, "unclosed '{open}' at {span}")
            }
            Self::InvalidUtf8 { span } => {
                write!(f, "invalid UTF-8 in string literal at {span}")
            }
        }
    }
}

impl std::error::Error for ParseError {}

