pub(crate) fn labeled_shape_of(a: &DenseArray) -> LabeledShape {
    let labels = a
        .labels()
        .map_or_else(|| vec![None; a.rank()], <[_]>::to_vec);
    LabeledShape::new(a.shape().dims().to_vec(), labels)
}

